(120, '6QCICF', 6, NULL, 'حنان عبدالهادي سليم', '48', '27506112700547', 'نجع الديري , قرية القبيبه . مركز فرشوط , محاظه قنا', 3247, 'فرشوط', 'القبيبة', '01128071372', NULL, 'ربة منزل', 'لا تعمل', NULL, 'مسكن مشترك', NULL, NULL, 'لا يوجد', NULL, 'مشترك', 'مشترك', 'عموميه', 'مسلح بطريقه قديمه علي قواعد عاديه  المساحة :  50 مترعدد الغرف : غرفة وصالة', 'الاسره مكونه من أربع أفراد غير الام و هي ارملة و مريضه بسرطان  ومنهم من هم في التعليم  في مراحل الابتدائية و الاعداديه و لم يستكمل بعضهم التعليم لعدم قدرة الام على تحمل مصاريفهم التعليميه', 'ربة المنزل تعاني من سرطان الدم', 'الاسره تحتاج الي الدعم حتي تستطيع مقاومة هذه الظروف المعيشية في ذالك الظروف لانها اسره فقيره جدا', 'الدخل لا يتناسب مع الانفاق والعلاج.لان الاعتماد الكلي للاسره على معاش تكافل وكرامه  كصفه دائمه وايضا تقوم بتربية بعض البهائم الصغيره مثل المعيز والخراف  وهذا يضخ مبلغ بسيط اخر العام', NULL, NULL, '2024-01-24', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 24, '6949291c9106d8e7c683e7713ebb1731.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 3, 0, NULL, NULL, '2023-03-17 08:44:29', '2024-01-03 13:07:27'),
